$('#hongye-drag-overlay').remove();

if (!window.hongyeAudioInstance) {
    window.hongyeAudioInstance = new Audio('https://files.catbox.moe/8y3qv2.mp3');
    window.hongyeAudioInstance.loop = true;
    window.hongyeAudioInstance.volume = 0.5;
}

$(document).off('.hongyeHandbook');

window.HONGYE_CONFIG = {
    storageCollapse: 'hongye_collapsed',
    storageTab: 'hongye_tab',
    storagePos: 'hongye_custom_pos'
};

let savedPos = localStorage.getItem(window.HONGYE_CONFIG.storagePos);
let initialPos = savedPos ? JSON.parse(savedPos) : { top: '80px', left: '10px' };

let hongyeState = {
    currentTab: localStorage.getItem(window.HONGYE_CONFIG.storageTab) || 'profile',
    isCollapsed: localStorage.getItem(window.HONGYE_CONFIG.storageCollapse) === 'true',
    isBgmOn: false
