function getMvuDataSafe() {
    const checkObj = (win) => {
        try {
            if (win.Mvu && typeof win.Mvu.getMvuData === 'function')
                return win.Mvu.getMvuData({ type: 'message', message_id: 'latest' })?.stat_data;
            if (win.mag_var_update && win.mag_var_update.data)
                return win.mag_var_update.data;
        } catch(e) { return null; }
    };
    return checkObj(window) || checkObj(window.parent) || checkObj(window.top);
}

const getVal = (data, path, def = 'Không có') => {
    if (!data) return def;
    let current = data;
    try {
        const keys = path.split('.');
        for (const key of keys) {
            if (current === undefined || current === null) return def;
            current = current[key];
        }
        return (current !== undefined && current !== null) ? current : def;
    } catch (e) { return def; }
};

function formatAncientTime(yearStr, dateStr) {
    if (!dateStr || dateStr === 'Không có') return 'Thời thần chưa định';
    const match = dateStr.match(/(\d{4})-(\d{2})-(\d{2})\s+(\d{2}):(\d{2})/);
    if (!match) return dateStr;
    const [_, y, m, d, h, min] = match;
    const cnNums = ['〇','Nhất','Nhị','Tam','Tứ','Ngũ','Lục','Thất','Bát','Cửu','Thập'];
    const toCn = (n) => {
        n = parseInt(n);
        if (n <= 10) return cnNums[n];
        if (n < 20) return 'Thập ' + (n%10===0?'':cnNums[n%10]);
        return cnNums[Math.floor(n/10)] + ' Thập ' + (n%10===0?'':cnNums[n%10]);
    };
    const dizhi = ['Tý','Sửu','Dần','Mão','Thìn','Tỵ','Ngọ','Mùi','Thân','Dậu','Tuất','Hợi'];
    const idx = Math.floor(((parseInt(h) + 1) % 24) / 2);
    let ke = '';
    if (parseInt(min) < 15) ke = 'Sơ khắc'; else if (parseInt(min) < 30) ke = 'Nhất khắc'; else if (parseInt(min) < 45) ke = 'Nhị khắc'; else ke = 'Tam khắc';
    const era = (yearStr && yearStr !== 'Không có' && isNaN(yearStr)) ? yearStr : `Thiên Phụng năm thứ ${toCn(parseInt(y)-2020 > 0 ? parseInt(y)-2020 : 1)}`;
    return `${yearStr === 'Không có' ? era : yearStr} · Tháng ${toCn(m)} Ngày ${toCn(d)} · Giờ ${dizhi[idx]} ${ke}`;
}

const renderModules = {
    profile: (sd) => {
        const name = getVal(sd, '主角.姓名', 'Chưa định');
        const gender = getVal(sd, '主角.性别', 'Chưa rõ');
        const age = getVal(sd, '主角.年龄', '0');
        const look = getVal(sd, '主角.外貌', 'Tạm chưa có mô tả');
        const silver = getVal(sd, '主角.现银', '0');
        const renderObj = (obj, emptyText) => {
            if (!obj || typeof obj !== 'object' || Object.keys(obj).length === 0)
                return `<div style="font-size:12px; color:var(--c-sub); padding:4px 0;">${emptyText}</div>`;
            return Object.entries(obj).map(([k, v]) =>
                `<div class="info-item"><span class="info-val" style="text-align:left;">${k}</span><span class="info-label" style="color:var(--c-main);">${v}</span></div>`
            ).join('');
        };
        return `
            <div class="profile-header drag-handle"><div class="profile-name">${name}</div></div>
            <div class="card-box">
                <div class="card-title">Hồ sơ nhân vật</div>
                <div class="info-item"><span class="info-label">Giới tính</span><span class="info-val">${gender}</span></div>
                <div class="info-item"><span class="info-label">Tuổi tác</span><span class="info-val">${age} Tuổi</span></div>
                <div class="info-item" style="align-items:flex-start;">
                    <span class="info-label" style="flex-shrink:0; margin-right:10px;">Tướng mạo</span>
                    <span class="info-val" style="text-align:right; font-weight:normal; line-height:1.4;">${look}</span>
                </div>
            </div>
            <div class="card-box"><div class="card-title">Tình duyên</div>${renderObj(getVal(sd, '主角.情缘', {}), 'Khách xem hồng trần, cô độc một mình')}</div>
            <div class="card-box">
                <div class="card-title">Thân gia tài sản</div>
                <div class="info-item"><span class="info-label hl-main">💰 Bạc mặt</span><span class="info-val hl-main">${silver} Lạng</span></div>
                <div style="margin-top:8px; border-top:1px dashed rgba(255,255,255,0.1); padding-top:8px;">
                    <div style="font-size:11px; color:var(--c-sub); margin-bottom:4px;">Sản nghiệp dưới danh nghĩa</div>${renderObj(getVal(sd, '主角.产业', {}), 'Tạm chưa có hằng sản')}
                </div>
            </div>
        `;
    },
    martial: (sd) => {
        const renderSkill = (title, path, empty) => {
            const data = getVal(sd, path, {});
            let content = '';
            if (!data || typeof data !== 'object' || Object.keys(data).length === 0) content = `<div style="font-size:12px; color:var(--c-sub); padding:4px;">${empty}</div>`;
            else content = Object.entries(data).map(([k, v]) => `<div class="info-item"><span class="info-val" style="text-align:left;">${k}</span><span class="info-label">${v}</span></div>`).join('');
            return `<div class="card-box"><div class="card-title">${title}</div>${content}</div>`;
        };
        return `${renderSkill('Nội gia công pháp', '武学.内功', 'Đan điền trống rỗng, chưa tu nội lực')}${renderSkill('Ngoại gia chiêu thức', '武学.外功', 'Chỉ biết vài thế võ sơ sài')}${renderSkill('Khinh công thân pháp', '武学.轻功', 'Bộ pháp nặng nề')}${renderSkill('Binh giáp vật phẩm', '武学.物品', 'Thân không vật ngoài thân')}`;
    },
    social: (sd) => {
        const tags = getVal(sd, '人脉.江湖标签', []);
        const interactions = getVal(sd, '人脉.近期互动', []);
        const relationMap = getVal(sd, '人脉.关系簿', {});
        let rList = [];
        if (typeof relationMap === 'object') for (let k in relationMap) rList.push({n:k, v:parseInt(relationMap[k])||0});
        const allies = rList.filter(r => r.v > 30).sort((a,b)=>b.v-a.v);
        const enemies = rList.filter(r => r.v < -30).sort((a,b)=>a.v-b.v);
        const renderTags = (arr) => (arr && arr.length && arr[0]!=='Không có') ? arr.map(t=>`<span style="display:inline-block; color:var(--c-main); background:rgba(238,187,136,0.1); padding:2px 8px; margin:2px; border-radius:2px; font-size:11px;">${t}</span>`).join('') : '<span style="color:var(--c-sub); font-size:12px;">Mới vào giang hồ, vô danh tiểu tốt</span>';
        const renderList = (arr, empty) => {
            if (!arr.length) return `<div style="font-size:12px; color:var(--c-sub);">${empty}</div>`;
            return arr.map(r => `<div class="info-item"><span class="info-val" style="text-align:left;">${r.n}</span><span class="info-label" style="color:var(--c-main); font-family:monospace;">${r.v>0?'+'+r.v:r.v}</span></div>`).join('');
        };
        const renderInter = (arr) => (arr && arr.length && arr[0]!=='Không có') ? arr.map(i=>`<div style="font-size:12px; color:var(--c-text); padding:4px 0; border-bottom:1px dotted rgba(255,255,255,0.1); line-height:1.4;">• ${i}</div>`).join('') : '<div style="font-size:12px; color:var(--c-sub);">Tạm không có vãng lai gần đây</div>';
        return `<div class="card-box"><div class="card-title">Thân phận giang hồ</div><div style="line-height:1.6;">${renderTags(tags)}</div></div><div class="card-box"><div class="card-title">Vãng lai gần đây</div>${renderInter(interactions)}</div><div class="card-box"><div class="card-title">Kết nghĩa đồng minh</div>${renderList(allies, 'Cô lập không viện trợ')}</div><div class="card-box"><div class="card-title">Túc địch thù gia</div>${renderList(enemies, 'Thế gian không kẻ thù')}</div>`;
    },
    intel: (sd) => {
        const year = getVal(sd, '世界.当前年号', 'Thiên Phụng năm đầu');
        const formattedTime = formatAncientTime(year, getVal(sd, '世界.当前日期', 'Không có'));
        const loc = getVal(sd, '世界.当前地点', 'Chưa rõ');
        const alignVal = parseInt(getVal(sd, '评价.正邪值', 0)) || 0;
        const renderAlignBar = (v) => {
            const pct = Math.min(100, Math.max(0, (v + 100) / 2));
            return `<div style="margin-bottom:12px; padding-bottom:8px;"><div style="display:flex; justify-content:space-between; font-size:12px; margin-bottom:6px;"><span style="color:var(--c-accent);">😈 Tà ma</span><span style="color:var(--c-main); font-weight:bold;">${v}</span><span style="color:var(--c-main);">Hiệp nghĩa 😇</span></div><div style="height:6px; background:rgba(255,255,255,0.1); border-radius:3px; overflow:hidden; position:relative;"><div style="position:absolute; left:${pct}%; top:0; bottom:0; width:4px; margin-left:-2px; background:#fff; box-shadow:0 0 4px #fff; z-index:2;"></div><div style="width:${pct}%; height:100%; background:linear-gradient(90deg, #d85c5c, #eebb88); opacity:0.5;"></div></div></div>`;
        };
        const evalList = [{ k: 'Võ học cảnh giới', v: getVal(sd, '评价.境界', 'Sơ quy môn kính') }, { k: 'Miếu đường thân phận', v: getVal(sd, '评价.庙堂', 'Phụng công thủ pháp') }, { k: 'Giang hồ uy vọng', v: getVal(sd, '评价.威望', 'Tịch tịch vô danh') }, { k: 'Hiệp nghĩa đánh giá', v: getVal(sd, '评价.侠义', 'Không ai hay biết') }];
        return `<div class="card-box" style="text-align:center;"><div style="font-weight:bold; color:var(--c-main); margin-bottom:6px; font-size:14px;">${formattedTime}</div><div style="font-size:12px; color:var(--c-sub);">📍 ${loc}</div></div><div class="card-box"><div class="card-title">Âm Quý Thiên Bảng</div><div style="font-size:13px; color:var(--c-text); line-height:1.4;">${getVal(sd, '世界.阴癸天榜', 'Chưa định')}</div></div><div class="card-box"><div class="card-title">Cực Lạc Địa Bảng</div><div style="font-size:13px; color:var(--c-text); line-height:1.4;">${getVal(sd, '世界.极乐地榜', 'Chưa định')}</div></div><div class="card-box"><div class="card-title">Lời đồn thị tỉnh</div><div style="font-size:13px; color:var(--c-text); line-height:1.4; ">${getVal(sd, '世界.江湖流言', 'Phong bình lãng tĩnh')}</div></div><div class="card-box"><div class="card-title">Giang hồ đánh giá</div>${renderAlignBar(alignVal)}${evalList.map(i => `<div class="info-item"><span class="info-label">${i.k}</span><span class="info-val hl-main">${i.v}</span></div>`).join('')}</div>`;
    }
};

function initDayiHandbook() {
    $('head').append(dayiStyles);
    $('body').prepend(dayiTemplate);
    const container = $('#dayi-handbook-container');
    const overlay = $('#hongye-drag-overlay');
    const content = $('#dh-content');

    container.css(initialPos);

    const render = () => {
        const sd = getMvuDataSafe() || {};
        const title = getVal(sd, '叙事.标题', 'Hồng Diệp Tàn Mộng');
        $('#dh-title').text(title === 'Chưa định' ? 'Hồng Diệp Tàn Mộng' : title);
        $('#dh-quote').text(getVal(sd, '叙事.引言', '...'));

        const bgmBtn = $('#btn-bgm');
        bgmBtn.text(hongyeState.isBgmOn ? '🔊' : '🔇');
        bgmBtn.css('opacity', hongyeState.isBgmOn ? '1' : '0.5');

        if (hongyeState.isCollapsed) container.addClass('collapsed');
        else container.removeClass('collapsed');

        const renderer = renderModules[hongyeState.currentTab] || renderModules.profile;
        content.html(renderer(sd));

        $('.nav-btn').removeClass('active');
        $(`.nav-btn[data-tab="${hongyeState.currentTab}"]`).addClass('active');
    };

    container.on('click', '.nav-btn', function(e) {
        e.stopPropagation();
        hongyeState.currentTab = $(this).data('tab');
        localStorage.setItem(window.HONGYE_CONFIG.storageTab, hongyeState.currentTab);
        render();
    });

    const toggleCollapse = (e) => {
        if (container.data('isDragging')) return;
        if(e && e.stopPropagation) e.stopPropagation();
        hongyeState.isCollapsed = !hongyeState.isCollapsed;
        localStorage.setItem(window.HONGYE_CONFIG.storageCollapse, hongyeState.isCollapsed);
        render();
    };

    container.on('click', '#btn-fold', toggleCollapse);

    const audio = window.hongyeAudioInstance;
    $(document).one('click', function() { if (hongyeState.isBgmOn && audio.paused) audio.play(); });
    container.on('click', '#btn-bgm', function(e) {
        e.stopPropagation();
        hongyeState.isBgmOn = !hongyeState.isBgmOn;
        render();
        if (hongyeState.isBgmOn) audio.play().catch(()=>{});
        else audio.pause();
    });

